script:
fields_to_track = ["status", "contact_date", "contact_by", "email_id"]

has_update = False
before_save = doc.get_doc_before_save()

if before_save:
    for field in fields_to_track:
        if doc.get(field) != before_save.get(field):
            has_update = True
            break

if has_update:
    doc.custom_background_update_time = frappe.utils.now_datetime()

# Server Script for Task - Before Save
if doc.is_follow_up_task:
    # Validate dates
    if doc.follow_up_date and doc.next_follow_up_date:
        from frappe.utils import getdate
        if getdate(doc.next_follow_up_date) <= getdate(doc.follow_up_date):
            frappe.throw("Next Follow Up Date should be after Follow Up Date")

    # Auto-generate subject if not provided
    if not doc.subject and doc.follow_up_type and doc.contact_with:
        doc.subject = f"Follow up via {doc.follow_up_type} with {doc.contact_with}"

    # Set expected end date to follow up date
    if doc.follow_up_date and not doc.exp_end_date:
        doc.exp_end_date = doc.follow_up_date

if doc.follow_up_activities:
    for row in doc.follow_up_activities:
        row.contact_with = doc.contact_person

# Duplicate Lead Check with Clickable Link (sandbox-safe)

fields_to_check = [
    ("email_id", "email"),
    ("mobile_no", "mobile number"),
    ("phone", "phone number"),
]

for field, label in fields_to_check:
    value = doc.get(field)
    if value:
        existing_lead = frappe.db.get_value("Lead", {field: value}, "name")
        if existing_lead and existing_lead != doc.name:
            frappe.throw(
                f"A Lead with this {label} already exists: "
                f"<a href='/app/lead/{existing_lead}' target='_blank'>{existing_lead}</a>"
            )

if doc.follow_up_activities:
    last_row = doc.follow_up_activities[-1]

    if last_row.inquiry_status:
        doc.latest_inquiry_status = last_row.inquiry_status

if doc.follow_up_activities:
    last_row = doc.follow_up_activities[-1]
    doc.latest_inquiry_status = last_row.inquiry_status or ""
else:
    doc.latest_inquiry_status = ""
